const Web3 = require('web3');
const Tx = require('ethereumjs-tx').Transaction;

const web3 = new Web3('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID');

const account1 = '0xYOUR_WALLET_ADDRESS';
const privateKey1 = Buffer.from('YOUR_PRIVATE_KEY', 'hex');

// Send ETH
const sendTransaction = async (to, value) => {
  const txCount = await web3.eth.getTransactionCount(account1);
  const txObject = {
    nonce: web3.utils.toHex(txCount),
    to,
    value: web3.utils.toHex(web3.utils.toWei(value, 'ether')),
    gasLimit: web3.utils.toHex(21000),
    gasPrice: web3.utils.toHex(web3.utils.toWei('10', 'gwei')),
  };

  const tx = new Tx(txObject, { chain: 'mainnet' });
  tx.sign(privateKey1);

  const serializedTx = tx.serialize();
  const raw = '0x' + serializedTx.toString('hex');

  const txHash = await web3.eth.sendSignedTransaction(raw);
  
  return txHash.transactionHash;
};

// Interact with smart contract
const contractABI = []; // Contract ABI array
const contractAddress = '0xCONTRACT_ADDRESS'; // Contract address

const contract = new web3.eth.Contract(contractABI, contractAddress);


const callContractMethod = async (methodName, params, value) => {
  const txCount = await web3.eth.getTransactionCount(account1);
  const txObject = {
    nonce: web3.utils.toHex(txCount),
    to: contractAddress,
    data: contract.methods[methodName](...params).encodeABI(), 
    value: web3.utils.toHex(web3.utils.toWei(value, 'ether')),
    gasLimit: web3.utils.toHex(60000),
    gasPrice: web3.utils.toHex(web3.utils.toWei('10', 'gwei')),
  };
  
  const tx = new Tx(txObject, { chain: 'mainnet' });  
  tx.sign(privateKey1);
  
  const serializedTx = tx.serialize();
  const raw = '0x' + serializedTx.toString('hex');
  
  const txHash = await web3.eth.sendSignedTransaction(raw);
  
  return txHash.transactionHash;
};